                if not isinstance(declaration[field], str):
                    return (
                        f"parameter '{name}' field '{field}' must be a string"
                    )

    return None


def _get_arg_value(declaration, arg_map):
    return arg_map.get(declaration["arg"]) if "arg" in declaration else None


def _get_file_value(declaration, arg_map):
    if "file" not in declaration:
        return None
    path = declaration["file"]
    try:
        if not os.path.isfile(path):
            return None
        with open(path, "r") as f:
            return f.read()
    except (OSError, IOError):
        return None


def _get_env_value(declaration, arg_map):
    return os.environ.get(declaration["env"]) if "env" in declaration else None


def _get_default_value(declaration, arg_map):
    return declaration.get("default")


_SOURCE_GETTERS = [
    ("arg", _get_arg_value),
    ("file", _get_file_value),
    ("env", _get_env_value),
    ("default", _get_default_value),
]


def resolve_parameter(name, declaration, arg_map):
    """Resolve a single parameter from its sources.

    Returns (value_string, None) on success.
    Returns (None, error_message) on parse failure.
    Returns (None, None) if no source provides a value.
    """
    param_type = declaration["type"]

    for source_name, getter in _SOURCE_GETTERS:
        raw_value = getter(declaration, arg_map)
        if not raw_value or not raw_value.strip():
            continue

        try:
            parsed = parse_value(raw_value.strip(), param_type)
            return (parsed, None)
        except ValueError as e:
            return (
                None,
                f"parameter '{name}': failed to parse from source "
                f"'{source_name}': {e}",
            )

    return (None, None)


def main():
    args = sys.argv[1:]

    if len(args) < 1:
        print("error: no schema file specified", file=sys.stderr)
        sys.exit(1)

    schema_path = args[0]
    arg_candidates = args[1:]

    # Load schema
    try:
        with open(schema_path, "r") as f:
            schema = json.load(f)
    except FileNotFoundError:
        print(f"error: schema file '{schema_path}' not found", file=sys.stderr)
        sys.exit(1)
    except json.JSONDecodeError as e:
        print(
            f"error: invalid JSON in schema file '{schema_path}': {e}",
            file=sys.stderr,
        )
        sys.exit(1)

    # Validate schema
    validation_error = validate_schema(schema)
    if validation_error:
        print(f"error: {validation_error}", file=sys.stderr)
        sys.exit(1)

    # Build arg map from CLI candidates
    arg_map = build_arg_map(arg_candidates)

    # Resolve all parameters
    resolved = {}
    unresolved = []

    for name, declaration in schema.items():
        value, error = resolve_parameter(name, declaration, arg_map)

        if error:
            # Parse failure halts immediately
            print(f"error: {error}", file=sys.stderr)
            sys.exit(1)

        if value is None:
            unresolved.append(name)
        else:
            resolved[name] = value

    # Check for unresolved parameters
    if unresolved:
        names = ", ".join(sorted(unresolved))
        print(
            f"error: unresolved parameters: {names}",
            file=sys.stderr,
        )
        sys.exit(1)

    # Success - write JSON to stdout
    print(json.dumps(resolved))
    sys.exit(0)


if __name__ == "__main__":
    main()

